diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 60da48e1d95d..48f679526913 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -6202,6 +6202,122 @@ Instruction *InstCombinerImpl::foldICmpEquality(ICmpInst &I) {
                                   : ConstantInt::getNullValue(A->getType()));
   }

+  // icmp eq/ne X, min(max(X, Lo), Hi) --> (X - Lo) u</u>= (Hi - Lo + 1)
+  {
+    Value *X, *Clamp = Op0;
+    const APInt *Lo, *Hi;
+    auto MatchClamp = [&](Value *V) -> bool {
+      IntrinsicInst *II = dyn_cast<IntrinsicInst>(V);
+      if (!II) return false;
+      if (II->getIntrinsicID() == Intrinsic::smin) {
+        // smin(smax(X, Lo), Hi)
+        if (match(II->getArgOperand(0),
+                  m_Intrinsic<Intrinsic::smax>(m_Value(X), m_APInt(Lo))) &&
+            match(II->getArgOperand(1), m_APInt(Hi)))
+          return true;
+        // smin(Hi, smax(X, Lo)) swapped
+        if (match(II->getArgOperand(1),
+                  m_Intrinsic<Intrinsic::smax>(m_Value(X), m_APInt(Lo))) &&
+            match(II->getArgOperand(0), m_APInt(Hi)))
+          return true;
+      } else if (II->getIntrinsicID() == Intrinsic::smax) {
+        // smax(smin(X, Hi), Lo)
+        if (match(II->getArgOperand(0),
+                  m_Intrinsic<Intrinsic::smin>(m_Value(X), m_APInt(Hi))) &&
+            match(II->getArgOperand(1), m_APInt(Lo)))
+          return true;
+        // smax(Lo, smin(X, Hi)) swapped
+        if (match(II->getArgOperand(1),
+                  m_Intrinsic<Intrinsic::smin>(m_Value(X), m_APInt(Hi))) &&
+            match(II->getArgOperand(0), m_APInt(Lo)))
+          return true;
+      }
+      // TODO: unsigned min/max.
+      return false;
+    };
+    if (MatchClamp(Clamp) && Op1 == X) {
+      // Lo <= Hi? If not, clamp is constant Hi (or Lo). For valid range check, ensure Lo <= Hi.
+      if (Lo->sle(*Hi)) {
+        APInt Diff = *Hi - *Lo + 1;
+        // Combine constants: X - Lo where X may already have a constant offset.
+        APInt TotalConst = -(*Lo);
+        Value *Var = X;
+        while (true) {
+          const APInt *C;
+          Value *A;
+          if (match(Var, m_Add(m_Value(A), m_APInt(C)))) {
+            TotalConst += *C;
+            Var = A;
+          } else if (match(Var, m_Add(m_APInt(C), m_Value(A)))) {
+            TotalConst += *C;
+            Var = A;
+          } else {
+            break;
+          }
+        }
+        // If TotalConst is zero, just use Var.
+        Value *XSubLo = TotalConst.isZero() ? Var :
+                        Builder.CreateAdd(Var, ConstantInt::get(X->getType(), TotalConst));
+        ICmpInst::Predicate NewPred = (Pred == ICmpInst::ICMP_EQ) ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGE;
+        return new ICmpInst(NewPred, XSubLo, ConstantInt::get(X->getType(), Diff));
+      }
+    }
+  }
+  // Also handle swapped operands.
+  {
+    Value *X, *Clamp = Op1;
+    const APInt *Lo, *Hi;
+    auto MatchClamp = [&](Value *V) -> bool {
+      IntrinsicInst *II = dyn_cast<IntrinsicInst>(V);
+      if (!II) return false;
+      if (II->getIntrinsicID() == Intrinsic::smin) {
+        if (match(II->getArgOperand(0),
+                  m_Intrinsic<Intrinsic::smax>(m_Value(X), m_APInt(Lo))) &&
+            match(II->getArgOperand(1), m_APInt(Hi)))
+          return true;
+        if (match(II->getArgOperand(1),
+                  m_Intrinsic<Intrinsic::smax>(m_Value(X), m_APInt(Lo))) &&
+            match(II->getArgOperand(0), m_APInt(Hi)))
+          return true;
+      } else if (II->getIntrinsicID() == Intrinsic::smax) {
+        if (match(II->getArgOperand(0),
+                  m_Intrinsic<Intrinsic::smin>(m_Value(X), m_APInt(Hi))) &&
+            match(II->getArgOperand(1), m_APInt(Lo)))
+          return true;
+        if (match(II->getArgOperand(1),
+                  m_Intrinsic<Intrinsic::smin>(m_Value(X), m_APInt(Hi))) &&
+            match(II->getArgOperand(0), m_APInt(Lo)))
+          return true;
+      }
+      return false;
+    };
+    if (MatchClamp(Clamp) && Op0 == X) {
+      if (Lo->sle(*Hi)) {
+        APInt Diff = *Hi - *Lo + 1;
+        // Combine constants: X - Lo where X may already have a constant offset.
+        APInt TotalConst = -(*Lo);
+        Value *Var = X;
+        while (true) {
+          const APInt *C;
+          Value *A;
+          if (match(Var, m_Add(m_Value(A), m_APInt(C)))) {
+            TotalConst += *C;
+            Var = A;
+          } else if (match(Var, m_Add(m_APInt(C), m_Value(A)))) {
+            TotalConst += *C;
+            Var = A;
+          } else {
+            break;
+          }
+        }
+        // If TotalConst is zero, just use Var.
+        Value *XSubLo = TotalConst.isZero() ? Var :
+                        Builder.CreateAdd(Var, ConstantInt::get(X->getType(), TotalConst));
+        ICmpInst::Predicate NewPred = (Pred == ICmpInst::ICMP_EQ) ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGE;
+        return new ICmpInst(NewPred, XSubLo, ConstantInt::get(X->getType(), Diff));
+      }
+    }
+  }
   if (auto *Res = foldICmpEqualityWithOffset(
           I, Builder, getSimplifyQuery().getWithInstruction(&I)))
     return Res;

